prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?org ?created ?origId ?normId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:belongsTo ?org . }
  OPTIONAL { ?model tai:modelCreated ?created . }
  FILTER(CONTAINS(LCASE(STR(?origId)), "1ad939eef40c461dafae27f75a0586d3") || 
         CONTAINS(LCASE(STR(?normId)), "1ad939eef40c461dafae27f75a0586d3") ||
         CONTAINS(LCASE(STR(?model)), "1ad939eef40c461dafae27f75a0586d3"))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gateway ?gatewayType ?direction ?name WHERE {
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?def .
  ?def tai:belongsTo ?model .
  ?model tai:originalId "1ad939eef40c461dafae27f75a0586d3" .
  ?gateway a bboExt:ExclusiveGateway .
  ?gateway tai:belongsTo ?choreo .
  OPTIONAL { ?gateway bbo:name ?name . }
  OPTIONAL { ?gateway bboExt:gatewayDirection ?direction . }
}
UNION
SELECT ?gateway ?gatewayType ?direction ?name WHERE {
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?def .
  ?def tai:belongsTo ?model .
  ?model tai:originalId "1ad939eef40c461dafae27f75a0586d3" .
  ?gateway a bboExt:EventBasedGateway .
  ?gateway tai:belongsTo ?choreo .
  OPTIONAL { ?gateway bbo:name ?name . }
  OPTIONAL { ?gateway bboExt:gatewayDirection ?direction . }
  OPTIONAL { ?gateway bboExt:eventGatewayType ?gatewayType . }
  OPTIONAL { ?gateway bboExt:instantiate ?instantiate . }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gateway ?type ?direction ?name ?instantiate ?eventGatewayType WHERE {
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?def .
  ?def tai:belongsTo ?model .
  ?model tai:originalId "1ad939eef40c461dafae27f75a0586d3" .
  ?gateway tai:belongsTo ?choreo .
  ?gateway a ?type .
  FILTER(?type IN (bboExt:ExclusiveGateway, bboExt:EventBasedGateway))
  OPTIONAL { ?gateway bbo:name ?name . }
  OPTIONAL { ?gateway bboExt:gatewayDirection ?direction . }
  OPTIONAL { ?gateway bboExt:instantiate ?instantiate . }
  OPTIONAL { ?gateway bboExt:eventGatewayType ?eventGatewayType . }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?sourceRef ?targetRef ?messageRef WHERE {
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?def .
  ?def tai:belongsTo ?model .
  ?model tai:originalId "1ad939eef40c461dafae27f75a0586d3" .
  ?flow a bboExt:MessageFlow .
  ?flow tai:belongsTo ?choreo .
  OPTIONAL { ?flow bboExt:sourceRef ?sourceRef . }
  OPTIONAL { ?flow bboExt:targetRef ?targetRef . }
  OPTIONAL { ?flow bboExt:messageRef ?messageRef . }
}
